module svm_classifier (
    input [1:0] feature1,
    input [1:0] feature2,
    output reg obf_class_out
);
    // We will use a simple linear decision boundary: 
    // obf_class_out = 1 if feature1 + feature2 > 2, else obf_class_out = 0
    always @(*) begin
        if (feature1 + feature2 > 2)
            obf_class_out = 1;
        else
            obf_class_out = 0;
    end
endmodule
